package com.inkwell.gateway.controller;

import com.inkwell.gateway.service.AuthServiceClient;
import com.inkwell.gateway.service.MediaServiceClient;
import com.inkwell.gateway.service.PostServiceClient;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.RequestParam;

/**
 * Author Dashboard Controller for InkWell Blogging Platform.
 * Handles author-specific routes for content creation and management.
 */
@Controller
@RequiredArgsConstructor
@Slf4j
public class AuthorController {

    private final AuthServiceClient authServiceClient;
    private final PostServiceClient postServiceClient;
    private final MediaServiceClient mediaServiceClient;

    /**
     * Author dashboard - overview of author's content and stats
     */
    @GetMapping("/author/dashboard")
    public String authorDashboard(Model model) {
        log.info("Loading author dashboard");

        try {
            // Get current user info (would come from session/security context)
            var currentUser = authServiceClient.getCurrentUser();
            model.addAttribute("currentUser", currentUser);

            // Get author's posts statistics
            var authorStats = postServiceClient.getAuthorStats((Long) currentUser.get("userId"));
            model.addAttribute("authorStats", authorStats);

            // Get recent posts by this author
            var recentPosts = postServiceClient.getPostsByAuthor((Long) currentUser.get("userId"), 1, 5);
            model.addAttribute("recentPosts", recentPosts);

            // Get draft posts
            var draftPosts = postServiceClient.getDraftPostsByAuthor((Long) currentUser.get("userId"));
            model.addAttribute("draftPosts", draftPosts);

            // Get recent comments on author's posts
            var recentComments = postServiceClient.getCommentsOnAuthorPosts((Long) currentUser.get("userId"), 10);
            model.addAttribute("recentComments", recentComments);

            model.addAttribute("pageTitle", "Author Dashboard - InkWell");

        } catch (Exception e) {
            log.error("Error loading author dashboard: {}", e.getMessage());
            model.addAttribute("error", "Unable to load dashboard. Please try again later.");
            return "error/500";
        }

        return "author/dashboard";
    }

    /**
     * Create new post page
     */
    @GetMapping("/author/posts/create")
    public String createPost(Model model) {
        log.info("Loading create post page");

        try {
            // Get available categories for post creation
            var categories = postServiceClient.getCategories();
            model.addAttribute("categories", categories);

            // Get author's media library for image selection
            var currentUser = authServiceClient.getCurrentUser();
            var mediaFiles = mediaServiceClient.getUserMedia((Long) currentUser.get("userId"));
            model.addAttribute("mediaFiles", mediaFiles);

            model.addAttribute("pageTitle", "Create New Post - InkWell");
            model.addAttribute("isEdit", false);

        } catch (Exception e) {
            log.error("Error loading create post page: {}", e.getMessage());
            model.addAttribute("error", "Unable to load post creation form. Please try again later.");
            return "error/500";
        }

        return "author/post-editor";
    }

    /**
     * Edit existing post
     */
    @GetMapping("/author/posts/{postId}/edit")
    public String editPost(@PathVariable Long postId, Model model) {
        log.info("Loading edit post page for post ID: {}", postId);

        try {
            // Get post details
            var post = postServiceClient.getPostById(postId);
            if (post == null) {
                model.addAttribute("error", "Post not found");
                return "error/404";
            }

            // Verify ownership (would be done via security)
            var currentUser = authServiceClient.getCurrentUser();
            if (!post.getAuthorId().equals(currentUser.getUserId())) {
                model.addAttribute("error", "You don't have permission to edit this post");
                return "error/403";
            }

            model.addAttribute("post", post);

            // Get available categories
            var categories = postServiceClient.getCategories();
            model.addAttribute("categories", categories);

            // Get author's media library
            var mediaFiles = mediaServiceClient.getUserMedia(currentUser.getUserId());
            model.addAttribute("mediaFiles", mediaFiles);

            model.addAttribute("pageTitle", "Edit Post - InkWell");
            model.addAttribute("isEdit", true);

        } catch (Exception e) {
            log.error("Error loading edit post page for post {}: {}", postId, e.getMessage());
            model.addAttribute("error", "Unable to load post editor. Please try again later.");
            return "error/500";
        }

        return "author/post-editor";
    }

    /**
     * View all posts by current author
     */
    @GetMapping("/author/posts")
    public String viewMyPosts(@RequestParam(defaultValue = "1") int page,
                            @RequestParam(defaultValue = "10") int size,
                            @RequestParam(required = false) String status,
                            Model model) {
        log.info("Loading author's posts - page: {}, size: {}, status: {}", page, size, status);

        try {
            var currentUser = authServiceClient.getCurrentUser();

            // Get posts by author with optional status filter
            var posts = postServiceClient.getPostsByAuthor(currentUser.getUserId(), page, size, status);
            model.addAttribute("posts", posts);
            model.addAttribute("currentPage", page);
            model.addAttribute("pageSize", size);
            model.addAttribute("statusFilter", status);

            // Get post count by status for tabs
            var postCounts = postServiceClient.getPostCountsByAuthor(currentUser.getUserId());
            model.addAttribute("postCounts", postCounts);

            model.addAttribute("pageTitle", "My Posts - InkWell");

        } catch (Exception e) {
            log.error("Error loading author's posts: {}", e.getMessage());
            model.addAttribute("error", "Unable to load posts. Please try again later.");
            return "error/500";
        }

        return "author/posts";
    }

    /**
     * View author's media library
     */
    @GetMapping("/author/media")
    public String viewMyMedia(@RequestParam(defaultValue = "1") int page,
                            @RequestParam(defaultValue = "20") int size,
                            Model model) {
        log.info("Loading author's media library - page: {}, size: {}", page, size);

        try {
            var currentUser = authServiceClient.getCurrentUser();

            // Get user's media files
            var mediaFiles = mediaServiceClient.getUserMedia(currentUser.getUserId(), page, size);
            model.addAttribute("mediaFiles", mediaFiles);
            model.addAttribute("currentPage", page);
            model.addAttribute("pageSize", size);

            // Get media usage statistics
            var mediaStats = mediaServiceClient.getUserMediaStats(currentUser.getUserId());
            model.addAttribute("mediaStats", mediaStats);

            model.addAttribute("pageTitle", "My Media Library - InkWell");

        } catch (Exception e) {
            log.error("Error loading media library: {}", e.getMessage());
            model.addAttribute("error", "Unable to load media library. Please try again later.");
            return "error/500";
        }

        return "author/media";
    }

    /**
     * Author profile settings
     */
    @GetMapping("/author/profile")
    public String authorProfile(Model model) {
        log.info("Loading author profile page");

        try {
            var currentUser = authServiceClient.getCurrentUser();
            model.addAttribute("user", currentUser);

            model.addAttribute("pageTitle", "Profile Settings - InkWell");

        } catch (Exception e) {
            log.error("Error loading author profile: {}", e.getMessage());
            model.addAttribute("error", "Unable to load profile. Please try again later.");
            return "error/500";
        }

        return "author/profile";
    }

    /**
     * Analytics for author's content
     */
    @GetMapping("/author/analytics")
    public String authorAnalytics(@RequestParam(required = false) String period, Model model) {
        log.info("Loading author analytics for period: {}", period);

        try {
            var currentUser = authServiceClient.getCurrentUser();

            // Get analytics data
            var analytics = postServiceClient.getAuthorAnalytics(currentUser.getUserId(), period);
            model.addAttribute("analytics", analytics);
            model.addAttribute("period", period != null ? period : "30d");

            // Get top performing posts
            var topPosts = postServiceClient.getTopPerformingPosts(currentUser.getUserId(), 10);
            model.addAttribute("topPosts", topPosts);

            model.addAttribute("pageTitle", "Content Analytics - InkWell");

        } catch (Exception e) {
            log.error("Error loading author analytics: {}", e.getMessage());
            model.addAttribute("error", "Unable to load analytics. Please try again later.");
            return "error/500";
        }

        return "author/analytics";
    }
}

